    languages: ['en-US'],
    outputFormat: 'wav',
    maxTextLength: 4000,
  },
  nim_magpie_zeroshot: {
    name: 'Magpie TTS Zeroshot',
    baseUrl: process.env.NIM_MAGPIE_ZERO_BASE_URL || null,
    defaultVoice: null,
    requiresAudioPrompt: true,  // Requires audio_prompt for voice cloning
    requiresTranscript: false,
    languages: ['en-US'],
