    maxTextLength: 4000,
  },
  nim_fastpitch: {
    name: 'FastPitch HifiGAN',
    baseUrl: process.env.NIM_FASTPITCH_BASE_URL || null,
    defaultVoice: null,           // FastPitch has a single default voice
    requiresAudioPrompt: false,
