    outputFormat: 'wav',
    maxTextLength: 4000,
  },
};

// ─── Module-Specific Chain Preferences ───────────────────────────
// Maps HireLoop modules to their optimal provider chain preferences
const MODULE_CHAINS = {
  // Mock Interview — needs quality LLM + TTS + ASR + Vision
  'mock-interview': {
    llm: 'quality',       // Best quality for evaluation
    tts: 'default',
    asr: 'default',
